#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
int main() {
    int n;
    cin >> n;
    TreeNode* root = new TreeNode(0);
    cin >> root->val;
    if (n > 1) {
        root->left = new TreeNode(0);
        cin >> root->left->val;
    }
    if (n > 2) {
        root->right = new TreeNode(0);
        cin >> root->right->val;
    }
    vector<int> res;
    stack<TreeNode*> s;
    TreeNode* cur = root;
    while (cur || !s.empty()) {
        while (cur) {
            s.push(cur);
            cur = cur->left;
        }
        cur = s.top();
        s.pop();
        res.push_back(cur->val);
        cur = cur->right;
    }
    for (int i = 0; i < res.size(); i++) {
        cout << res[i] << " ";
    }
    return 0;
}
